import{_ as e,a as t,b as r,c as d}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as c,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup এবং Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/redundant-backup-and-read-source.md","filePath":"bn-BD/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),p={name:"bn-BD/Other/redundant-backup-and-read-source.md"};function u(s,a,o,h,b,k){return n(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="redundant-backup-এবং-read-source-switching" tabindex="-1">Redundant Backup এবং Read Source Switching <a class="header-anchor" href="#redundant-backup-এবং-read-source-switching" aria-label="Permalink to &quot;Redundant Backup এবং Read Source Switching&quot;">​</a></h1><p>Redundant backup already uploaded file-এর একটি extra copy store করে।</p><p>Primary file এবং backup file দুটিই read sources হিসেবে ব্যবহার করা যায়। Visitors সাধারণত কোনো পার্থক্য দেখে না। পার্থক্য শুধু কোন storage channel file serve করছে।</p><h2 id="redundant-backup-কী-করতে-পারে" tabindex="-1">Redundant Backup কী করতে পারে <a class="header-anchor" href="#redundant-backup-কী-করতে-পারে" aria-label="Permalink to &quot;Redundant Backup কী করতে পারে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Extra copy store</td><td>Single channel failure-এর risk কমাতে files অন্য upload channel-এ back up করে।</td></tr><tr><td>Read source switch</td><td>Backup সফল হলে file reads primary channel এবং backup channel-এর মধ্যে switch করে।</td></tr><tr><td>Single-file backup</td><td>File details page থেকে একটি file back up করুন।</td></tr><tr><td>Batch backup</td><td>Admin page-এ multiple files select করে একসঙ্গে back up করুন।</td></tr><tr><td>Global redundant backup</td><td>Other Settings থেকে folder অনুযায়ী files back up করুন।</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>খুলুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>Folder বা সব files-এ bulk backup যোগ করার জন্য এই entry ভালো।</p><p>Backup channel manually select করা যায়, অথবা automatic switching বেছে নিয়ে ImgBed-কে suitable backup channel খুঁজতে দিতে পারেন।</p><h2 id="file-details-থেকে-backup" tabindex="-1">File Details থেকে Backup <a class="header-anchor" href="#file-details-থেকে-backup" aria-label="Permalink to &quot;File Details থেকে Backup&quot;">​</a></h2><p>Admin panel-এ file details page খুলে backup ক্লিক করুন।</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>একটি important file on demand back up করার জন্য এটি সবচেয়ে ভালো।</p><p>Backup successful হলে file details page available read sources দেখায়।</p><h2 id="selection-দিয়ে-batch-backup" tabindex="-1">Selection দিয়ে Batch Backup <a class="header-anchor" href="#selection-দিয়ে-batch-backup" aria-label="Permalink to &quot;Selection দিয়ে Batch Backup&quot;">​</a></h2><p>Admin panel-এ multiple files select করে batch backup run করুন।</p><p><img src="'+r+'" alt="Batch backup" loading="lazy"></p><p>Files-এর একটি group process করার জন্য এটি ভালো।</p><p>Selection backup, file details backup এবং Other Settings-এর redundant backup একই backup system ব্যবহার করে। এগুলো শুধু আলাদা entry points।</p><h2 id="backup-এর-পর-read-source-switch" tabindex="-1">Backup-এর পর Read Source Switch <a class="header-anchor" href="#backup-এর-পর-read-source-switch" aria-label="Permalink to &quot;Backup-এর পর Read Source Switch&quot;">​</a></h2><p>Backup complete হলে file details page read source switch করতে দেয়:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>Original upload channel থেকে read করে।</td></tr><tr><td>Backup channel</td><td>Backup channel থেকে read করে।</td></tr></tbody></table><p><img src="'+d+'" alt="Switch read source after backup" loading="lazy"></p><p>Visitors-কে file primary channel নাকি backup channel থেকে serve হচ্ছে জানতে হয় না।</p><p>আপনি যে read source নির্বাচন করেন সেটিই পরে file access-এর preferred source হয়।</p><h2 id="backup-কখন-skip-হয়" tabindex="-1">Backup কখন Skip হয় <a class="header-anchor" href="#backup-কখন-skip-হয়" aria-label="Permalink to &quot;Backup কখন Skip হয়&quot;">​</a></h2><p>নিচের cases backup-এর সময় skip হয়। এগুলো errors নয়।</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>যে file-এর backup আগে থেকেই আছে সেটি আবার back up করা হয় না।</td></tr><tr><td>Primary এবং backup channels একই</td><td>Meaningful backup-এর জন্য copy অন্য channel-এ store হতে হবে।</td></tr><tr><td>No usable backup channel</td><td>Suitable alternative channel available নেই।</td></tr></tbody></table><p>সংক্ষেপে: backups অন্য channel-এ যেতে হবে, এবং already backed-up files আবার extra space consume করে না।</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>File প্রথম upload হওয়ার সময় যে channel ব্যবহার হয়েছে।</td></tr><tr><td>Backup channel</td><td>Redundant copy যেখানে stored।</td></tr><tr><td>Primary read source</td><td>File currently primary channel থেকে read হচ্ছে।</td></tr><tr><td>Backup read source</td><td>File currently backup channel থেকে read হচ্ছে।</td></tr></tbody></table><p>Primary এবং backup read sources-এর user-facing behavior একই।</p><p>Backup file available থাকলে backup read source-এ switch করার পর images, videos এবং download links কাজ করতে থাকে।</p><h2 id="file-delete-হলে-কী-হয়" tabindex="-1">File Delete হলে কী হয় <a class="header-anchor" href="#file-delete-হলে-কী-হয়" aria-label="Permalink to &quot;File Delete হলে কী হয়&quot;">​</a></h2><p>File delete করলে ImgBed primary file এবং backup file দুটোই delete করে।</p>',37)])])}const g=c(p,[["render",u]]);export{y as __pageData,g as default};
